import React, { Suspense, lazy } from 'react';
import { BrowserRouter, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { DashboardProvider } from './context/DashboardContext';

// Lazy load components for performance optimization
const Landing = lazy(() => import('./pages/Landing'));
const Auth = lazy(() => import('./pages/Auth'));
const DashboardLayout = lazy(() => import('./components/layout/DashboardLayout'));
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Sentiment = lazy(() => import('./pages/Sentiment'));
const Topics = lazy(() => import('./pages/Topics'));
const RAG = lazy(() => import('./pages/RAG'));
const Profile = lazy(() => import('./pages/Profile'));

import ProtectedRoute from './components/auth/ProtectedRoute';

const LoadingFallback = () => (
  <div className="min-h-screen flex items-center justify-center bg-white">
    <div className="flex flex-col items-center gap-4">
      <div className="w-12 h-12 border-4 border-sky-500 border-t-transparent rounded-full animate-spin"></div>
      <p className="text-slate-500 font-medium animate-pulse">Loading experience...</p>
    </div>
  </div>
);

function App() {
  return (
    <AuthProvider>
      <DashboardProvider>
        <BrowserRouter>
          <Suspense fallback={<LoadingFallback />}>
            <Routes>
              {/* Public Routes */}
              <Route path="/" element={<Landing />} />
              <Route path="/login" element={<Auth />} />
              <Route path="/signup" element={<Auth />} />

              {/* Protected Routes (Authenticated) */}
              <Route element={<ProtectedRoute />}>
                <Route path="/dashboard" element={<DashboardLayout />}>
                  <Route index element={<Dashboard />} />
                  <Route path="sentiment" element={<Sentiment />} />
                  <Route path="topics" element={<Topics />} />
                  <Route path="rag" element={<RAG />} />
                  <Route path="profile" element={<Profile />} />
                </Route>
              </Route>

              {/* Fallback */}
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </Suspense>
        </BrowserRouter>
      </DashboardProvider>
    </AuthProvider>
  );
}

export default App;

import React from 'react';
import { TrendingUp, TrendingDown, Minus } from 'lucide-react';

const MetricCard = ({ title, value, unit, change, changeType, icon: Icon }) => {
    return (
        <div className="card hover:-translate-y-1 hover:shadow-lg hover:shadow-black/20 transition-all duration-300">
            <div className="flex justify-between items-start mb-4">
                <div className="p-2.5 bg-accent-primary/10 rounded-xl border border-accent-primary/20">
                    <Icon className="w-5 h-5 text-accent-primary" />
                </div>
                <div className={`flex items-center text-xs font-bold px-2.5 py-1 rounded-full border ${changeType === 'up' ? 'bg-sentiment-positive/10 text-sentiment-positive border-sentiment-positive/20' :
                        changeType === 'down' ? 'bg-sentiment-negative/10 text-sentiment-negative border-sentiment-negative/20' :
                            'bg-bg-primary text-text-secondary border-border-dark'
                    }`}>
                    {changeType === 'up' && <TrendingUp className="w-3.5 h-3.5 mr-1" />}
                    {changeType === 'down' && <TrendingDown className="w-3.5 h-3.5 mr-1" />}
                    {changeType === 'stable' && <Minus className="w-3.5 h-3.5 mr-1" />}
                    {change}
                </div>
            </div>
            <div>
                <p className="text-sm text-text-secondary font-medium tracking-wide mb-1">{title}</p>
                <div className="flex items-baseline space-x-1">
                    <h3 className="text-3xl font-bold text-text-primary tracking-tight">{value}</h3>
                    {unit && <span className="text-sm font-semibold text-text-secondary">{unit}</span>}
                </div>
            </div>
        </div>
    );
};

export default MetricCard;

import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import {
    LayoutDashboard,
    BarChart3,
    PieChart,
    Search,
    AlertCircle,
    LogOut,
    User,
    Activity
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { authService } from '../../services/authService';
import { motion } from 'framer-motion';

const Sidebar = () => {
    const navigate = useNavigate();

    const navItems = [
        { name: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
        { name: 'Sentiment Analysis', path: '/dashboard/sentiment', icon: PieChart },
        { name: 'Topic Insights', path: '/dashboard/topics', icon: BarChart3 },
        { name: 'Insights Assistant', path: '/dashboard/rag', icon: Search },
        { name: 'User Profile', path: '/dashboard/profile', icon: User },
    ];

    const handleLogout = async () => {
        try {
            await authService.signOut();
            navigate('/login', { replace: true });
        } catch (error) {
            console.error('Logout failed', error);
        }
    };

    return (
        <div className="w-64 bg-bg-secondary/90 backdrop-blur-xl h-screen border-r border-border-dark flex flex-col fixed left-0 top-0 pt-6 z-20 shadow-2xl">
            <div className="px-6 mb-8 flex items-center space-x-3">
                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-accent-primary to-accent-secondary flex items-center justify-center shadow-lg shadow-accent-primary/20">
                    <Activity className="w-5 h-5 text-white" />
                </div>
                <span className="text-xl font-bold text-text-primary tracking-tight">AI Forecaster</span>
            </div>

            <nav className="flex-1 px-4 space-y-2">
                {navItems.map((item) => (
                    <NavLink
                        key={item.name}
                        to={item.path}
                        className={({ isActive }) => `
                            flex items-center px-4 py-3 text-sm font-semibold rounded-xl transition-all duration-300 relative group overflow-hidden
                            ${isActive
                                ? 'bg-accent-primary/10 text-accent-primary shadow-[inset_0px_0px_20px_rgba(99,102,241,0.15)] ring-1 ring-accent-primary/30'
                                : 'text-text-secondary hover:bg-bg-primary hover:text-text-primary hover:scale-[1.02]'}
                        `}
                    >
                        {({ isActive }) => (
                            <>
                                <item.icon className="w-5 h-5 mr-3 z-10" />
                                <span className="z-10">{item.name}</span>
                                {isActive && (
                                    <motion.div
                                        layoutId="activeGlow"
                                        className="absolute inset-0 bg-accent-primary/5 rounded-xl z-0"
                                        initial={false}
                                        transition={{ type: "spring", stiffness: 300, damping: 30 }}
                                    >
                                        <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-accent-primary rounded-r-md shadow-[0_0_10px_rgba(99,102,241,0.8)]" />
                                    </motion.div>
                                )}
                            </>
                        )}
                    </NavLink>
                ))}
            </nav>

            <div className="p-4 space-y-4">
                <div className="bg-bg-primary rounded-xl p-4 border border-border-dark shadow-inner">
                    <div className="flex items-center text-xs font-bold text-text-secondary uppercase tracking-wider mb-2">
                        <AlertCircle className="w-4 h-4 mr-1 text-sentiment-positive" />
                        System Status
                    </div>
                    <div className="text-sm text-text-primary font-medium">
                        Operational. Data updated.
                    </div>
                </div>

                <button
                    onClick={handleLogout}
                    className="w-full flex items-center px-4 py-3 text-sm font-semibold text-text-secondary rounded-xl hover:bg-sentiment-negative/10 hover:text-sentiment-negative transition-all hover:scale-[1.02]"
                >
                    <LogOut className="w-5 h-5 mr-3" />
                    Sign Out
                </button>
            </div>
        </div>
    );
};

export default Sidebar;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabase } from '../services/supabase';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [session, setSession] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Initial setup
        supabase.auth.getSession().then(({ data: { session } }) => {
            setSession(session);
            setUser(session?.user ?? null);
            setLoading(false);
        });

        // Listen for changes
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setSession(session);
            setUser(session?.user ?? null);
            setLoading(false);
        });

        return () => subscription.unsubscribe();
    }, []);

    return (
        <AuthContext.Provider value={{
            user,
            session,
            token: session?.access_token || null,
            loading
        }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import React, { createContext, useContext, useState } from 'react';

const DashboardContext = createContext();

export const DashboardProvider = ({ children }) => {
    const [range, setRange] = useState('L7D');
    const [selectedSector, setSelectedSector] = useState('All Sectors');

    const updateRange = (newRange) => setRange(newRange);
    const updateSector = (newSector) => setSelectedSector(newSector);

    return (
        <DashboardContext.Provider value={{
            range,
            selectedSector,
            updateRange,
            updateSector
        }}>
            {children}
        </DashboardContext.Provider>
    );
};

export const useDashboard = () => {
    const context = useContext(DashboardContext);
    if (!context) {
        throw new Error('useDashboard must be used within a DashboardProvider');
    }
    return context;
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Mail, Lock, User, Phone, Loader2, ArrowRight, Facebook, Github, Linkedin } from 'lucide-react';
import { authService } from '../services/authService';
import AuthLayout from '../components/auth/AuthLayout';

const Auth = () => {
    const navigate = useNavigate();
    const location = useLocation();

    const from = location.state?.from?.pathname || '/dashboard';

    const [isLogin, setIsLogin] = useState(location.pathname === '/login');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState('');

    // Form States
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [name, setName] = useState('');
    const [phoneNumber, setPhoneNumber] = useState('');
    const [showPhoneLogin, setShowPhoneLogin] = useState(false);

    useEffect(() => {
        setIsLogin(location.pathname === '/login');
        setError('');
    }, [location.pathname]);

    const handleToggle = (toLogin) => {
        setIsLogin(toLogin);
        navigate(toLogin ? '/login' : '/signup', { replace: true });
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setIsSubmitting(true);
        try {
            await authService.signIn(email, password);
            navigate(from, { replace: true });
        } catch (err) {
            setError(err.message || 'Invalid email or password');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSignup = async (e) => {
        e.preventDefault();
        setError('');

        if (password !== confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        setIsSubmitting(true);
        try {
            await authService.signUp(email, password);
            navigate(from, { replace: true });
        } catch (err) {
            setError(err.message || 'Registration failed');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleGoogleLogin = async () => {
        setIsSubmitting(true);
        try {
            await authService.signInWithGoogle();
            // Google OAuth redirects are handled manually in authService
        } catch (err) {
            setError('Google login failed');
        } finally {
            setIsSubmitting(false);
        }
    };

    const loginForm = (
        <form className="space-y-5 w-full" onSubmit={handleLogin}>
            <h1 className="text-4xl font-bold text-gray-800 mb-2">Sign In</h1>

            {/* Social Icons - Small circular icons */}
            <div className="flex justify-center gap-3 mb-6">
                <button type="button" onClick={handleGoogleLogin} className="p-2.5 border border-gray-200 rounded-full text-gray-600 hover:bg-gray-50 hover:border-blue-500 hover:text-blue-500 transition-all">
                    <svg className="w-5 h-5" viewBox="0 0 24 24">
                        <path fill="currentColor" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                        <path fill="currentColor" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                        <path fill="currentColor" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" />
                        <path fill="currentColor" d="M12 5.38c1.62 0 3.06.56 4.21 1.66l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                    </svg>
                </button>
                <button type="button" className="p-2.5 border border-gray-200 rounded-full text-gray-600 hover:bg-gray-50 hover:border-blue-500 hover:text-blue-500 transition-all">
                    <Facebook className="w-5 h-5" />
                </button>
                <button type="button" className="p-2.5 border border-gray-200 rounded-full text-gray-600 hover:bg-gray-50 hover:border-blue-500 hover:text-blue-500 transition-all">
                    <Linkedin className="w-5 h-5" />
                </button>
            </div>

            <p className="text-gray-400 text-sm mb-6">or use your email account</p>

            {error && !isLogin && <div className="text-red-500 text-xs mb-2">{error}</div>}
            {error && isLogin && <div className="p-3 bg-red-50 text-red-600 text-xs rounded-xl mb-4 animate-shake">{error}</div>}

            <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-500 transition-colors">
                    <Mail className="w-5 h-5" />
                </div>
                <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                    placeholder="Email"
                />
            </div>

            <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-500 transition-colors">
                    <Lock className="w-5 h-5" />
                </div>
                <input
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                    placeholder="Password"
                />
            </div>

            <div className="text-right">
                <button type="button" className="text-sm text-gray-400 hover:text-blue-600 transition-colors">
                    Forgot your password?
                </button>
            </div>

            <button
                type="submit"
                disabled={isSubmitting}
                className="w-full bg-blue-600 text-white font-bold py-3.5 rounded-full shadow-lg shadow-blue-500/30 hover:bg-blue-700 hover:shadow-blue-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center mt-4"
            >
                {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : 'SIGN IN'}
            </button>
        </form>
    );

    const signupForm = (
        <form className="space-y-5 w-full" onSubmit={handleSignup}>
            <h1 className="text-4xl font-bold text-gray-800 mb-2">Create Account</h1>

            {/* Social Icons */}
            <div className="flex justify-center gap-3 mb-6">
                <button type="button" onClick={handleGoogleLogin} className="p-2.5 border border-gray-200 rounded-full text-gray-600 hover:bg-gray-50 hover:border-blue-500 hover:text-blue-500 transition-all">
                    <svg className="w-5 h-5" viewBox="0 0 24 24">
                        <path fill="currentColor" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                        <path fill="currentColor" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                        <path fill="currentColor" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" />
                        <path fill="currentColor" d="M12 5.38c1.62 0 3.06.56 4.21 1.66l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                    </svg>
                </button>
                <button type="button" className="p-2.5 border border-gray-200 rounded-full text-gray-600 hover:bg-gray-50 hover:border-blue-500 hover:text-blue-500 transition-all">
                    <Facebook className="w-5 h-5" />
                </button>
                <button type="button" className="p-2.5 border border-gray-200 rounded-full text-gray-600 hover:bg-gray-50 hover:border-blue-500 hover:text-blue-500 transition-all">
                    <Linkedin className="w-5 h-5" />
                </button>
            </div>

            <p className="text-gray-400 text-sm mb-6">or use your email for registration</p>

            {error && !isLogin && <div className="p-3 bg-red-50 text-red-600 text-xs rounded-xl mb-4 animate-shake">{error}</div>}

            <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-500 transition-colors">
                    <User className="w-5 h-5" />
                </div>
                <input
                    type="text"
                    required
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                    placeholder="Name"
                />
            </div>

            <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-500 transition-colors">
                    <Mail className="w-5 h-5" />
                </div>
                <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                    placeholder="Email"
                />
            </div>

            <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-500 transition-colors">
                    <Lock className="w-5 h-5" />
                </div>
                <input
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                    placeholder="Password"
                />
            </div>

            <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-500 transition-colors">
                    <Lock className="w-5 h-5" />
                </div>
                <input
                    type="password"
                    required
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                    placeholder="Confirm Password"
                />
            </div>

            <button
                type="submit"
                disabled={isSubmitting}
                className="w-full bg-blue-600 text-white font-bold py-3.5 rounded-full shadow-lg shadow-blue-500/30 hover:bg-blue-700 hover:shadow-blue-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center mt-4"
            >
                {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : 'SIGN UP'}
            </button>
        </form>
    );

    return (
        <AuthLayout
            isLogin={isLogin}
            setIsLogin={handleToggle}
            loginForm={loginForm}
            signupForm={signupForm}
        />
    );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import {
    Database,
    Smile,
    Frown,
    Hash,
    TrendingUp,
    ChevronRight,
    ArrowUpRight,
    ArrowDownRight,
    Activity
} from 'lucide-react';
import MetricCard from '../components/cards/MetricCard';
import SentimentPieChart from '../components/charts/SentimentPieChart';
import SentimentTrendChart from '../components/charts/SentimentTrendChart';
import DashboardHeader from '../components/layout/DashboardHeader';
import { useDashboard } from '../context/DashboardContext';
import { useNavigate } from 'react-router-dom';
import * as api from '../services/api';

const Dashboard = () => {
    const navigate = useNavigate();
    const { range, selectedSector } = useDashboard();
    const [stats, setStats] = useState(null);
    const [distribution, setDistribution] = useState(null);
    const [trend, setTrend] = useState(null);
    const [sectors, setSectors] = useState([]);
    const [liveSignals, setLiveSignals] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchData = async () => {
        setLoading(true);
        try {
            const filters = { range, sector: selectedSector };
            const [s, d, t, sec, ls] = await Promise.all([
                api.getStats(filters),
                api.getSentimentDistribution(filters),
                api.getSentimentTrend(filters),
                api.getSectorSentiment(),
                api.getLiveSignals()
            ]);
            setStats(s);
            setDistribution(d);
            setTrend(t);
            setSectors(sec);
            setLiveSignals(ls);
        } catch (error) {
            console.error("Error fetching dashboard data", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, [range, selectedSector]);

    if (loading && !stats) return (
        <div className="flex items-center justify-center min-h-[400px]">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-accent-primary"></div>
        </div>
    );

    return (
        <div className="space-y-8 pb-12">
            <DashboardHeader
                title="Market Overview"
                subtitle="Global consumer sentiment and emerging trend analysis."
                onRefresh={fetchData}
                loading={loading}
            />

            {/* Premium Metric Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <MetricCard
                    title="Analyzed Signals"
                    value={stats?.totalDataPoints.toLocaleString()}
                    change="+12.5%"
                    changeType="up"
                    icon={Database}
                />
                <MetricCard
                    title="Positive Momentum"
                    value={stats?.positiveSentiment}
                    unit="%"
                    change="+3.2%"
                    changeType="up"
                    icon={Smile}
                />
                <MetricCard
                    title="Negative Friction"
                    value={stats?.negativeSentiment}
                    unit="%"
                    change="-1.5%"
                    changeType="down"
                    icon={Frown}
                />
                <MetricCard
                    title="Detected Clusters"
                    value={stats?.activeTopics}
                    change="Stable"
                    changeType="stable"
