export default Landing;

import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Mail, Lock, Phone, Loader2, ArrowRight } from 'lucide-react';
import { authService } from '../services/authService';
import AuthLayout from '../components/auth/AuthLayout';

const Login = () => {
    const navigate = useNavigate();
    const location = useLocation();

    const from = location.state?.from?.pathname || '/dashboard';

    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [phoneNumber, setPhoneNumber] = useState('');
    const [otp, setOtp] = useState('');
    const [otpSent, setOtpSent] = useState(false);
    const [showPhoneLogin, setShowPhoneLogin] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setIsSubmitting(true);
        try {
            await authService.signIn(email, password);
            navigate(from, { replace: true });
        } catch (err) {
            setError(err.message || 'Invalid email or password');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleGoogleLogin = async () => {
        setIsSubmitting(true);
        try {
            await authService.signInWithGoogle();
            // Google OAuth redirects are handled in authService itself
        } catch (err) {
            setError('Google login failed. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handlePhoneLogin = async (e) => {
        e.preventDefault();
        setError('');
        setIsSubmitting(true);
        try {
            await authService.signInWithOtp(phoneNumber);
            setOtpSent(true);
        } catch (err) {
            setError(err.message || 'Failed to send OTP. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleVerifyOtp = async (e) => {
        e.preventDefault();
        setError('');
        setIsSubmitting(true);
        try {
            await authService.verifyOtp(phoneNumber, otp);
            navigate(from, { replace: true });
        } catch (err) {
            setError(err.message || 'Invalid OTP. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <AuthLayout
            mode="login"
            title="Sign In"
            subtitle="or use your account"
            footerText="Don't have an account?"
            footerLink="/signup"
            footerLinkText="Sign Up"
        >
            {error && (
                <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 text-sm rounded-r-lg animate-shake">
                    {error}
                </div>
            )}

            {!showPhoneLogin ? (
                <form className="space-y-5" onSubmit={handleSubmit}>
                    <div className="relative group">
                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                            <Mail className="w-5 h-5" />
                        </div>
                        <input
                            type="email"
                            required
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                            placeholder="Email"
                        />
                    </div>

                    <div className="relative group">
                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                            <Lock className="w-5 h-5" />
                        </div>
                        <input
                            type="password"
                            required
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                            placeholder="Password"
                        />
                    </div>

                    <div className="text-right">
                        <button type="button" className="text-sm text-gray-400 hover:text-teal-600 transition-colors">
                            Forgot your password?
                        </button>
                    </div>

                    <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full bg-teal-500 text-white font-bold py-4 rounded-full shadow-lg shadow-teal-500/30 hover:bg-teal-600 hover:shadow-teal-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center"
                    >
                        {isSubmitting ? (
                            <Loader2 className="w-6 h-6 animate-spin" />
                        ) : (
                            <>
                                SIGN IN
                                <ArrowRight className="w-5 h-5 ml-2" />
                            </>
                        )}
                    </button>

                    <div className="relative flex items-center py-2">
                        <div className="flex-grow border-t border-gray-200"></div>
                        <span className="flex-shrink-0 mx-4 text-gray-400 text-sm font-medium">OR</span>
                        <div className="flex-grow border-t border-gray-200"></div>
                    </div>

                    <button
                        type="button"
                        onClick={handleGoogleLogin}
                        disabled={isSubmitting}
                        className="w-full bg-white border border-gray-300 text-gray-700 font-bold py-3.5 rounded-full hover:bg-gray-50 hover:shadow-md transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center shadow-sm"
                    >
                        <svg className="w-5 h-5 mr-3" viewBox="0 0 24 24">
                            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                        </svg>
                        Continue with Google
                    </button>

                    <button
                        type="button"
                        onClick={() => setShowPhoneLogin(true)}
                        className="w-full text-center text-sm font-semibold text-gray-500 hover:text-teal-600 flex items-center justify-center gap-2"
                    >
                        <Phone className="w-4 h-4" />
                        Use Phone Number
                    </button>
                </form>
            ) : (
                <form className="space-y-5" onSubmit={otpSent ? handleVerifyOtp : handlePhoneLogin}>
                    {!otpSent ? (
                        <>
                            <div className="relative group">
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                                    <Phone className="w-5 h-5" />
                                </div>
                                <input
                                    type="tel"
                                    required
                                    value={phoneNumber}
                                    onChange={(e) => setPhoneNumber(e.target.value)}
                                    className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                                    placeholder="Phone Number (e.g., +1234567890)"
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={isSubmitting}
                                className="w-full bg-teal-500 text-white font-bold py-4 rounded-full shadow-lg shadow-teal-500/30 hover:bg-teal-600 hover:shadow-teal-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center"
                            >
                                {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : 'SEND OTP'}
                            </button>
                        </>
                    ) : (
                        <>
                            <div className="relative group">
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                                    <Lock className="w-5 h-5" />
                                </div>
                                <input
                                    type="text"
                                    required
                                    value={otp}
                                    onChange={(e) => setOtp(e.target.value)}
                                    className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                                    placeholder="Enter OTP"
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={isSubmitting}
                                className="w-full bg-teal-500 text-white font-bold py-4 rounded-full shadow-lg shadow-teal-500/30 hover:bg-teal-600 hover:shadow-teal-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center"
                            >
                                {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : 'VERIFY OTP'}
                            </button>
                        </>
                    )}

                    <button
                        type="button"
                        onClick={() => {
                            setShowPhoneLogin(false);
                            setOtpSent(false);
                            setOtp('');
                        }}
                        className="w-full text-center text-sm font-semibold text-gray-500 hover:text-teal-600"
                    >
                        Back to Email Login
                    </button>
                </form>
            )}
        </AuthLayout>
    );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import {
    Send,
    Bot,
    Sparkles,
    Copy,
    ThumbsUp,
    ThumbsDown,
    RefreshCw,
    Database
} from 'lucide-react';
import * as api from '../services/api';

const RAG = () => {
    const location = useLocation();
    const [query, setQuery] = useState('');
    const [response, setResponse] = useState(null);
    const [loading, setLoading] = useState(false);
    const [history, setHistory] = useState([]);

    const handleAskAI = async (e, customQuery) => {
        if (e) e.preventDefault();
        const finalQuery = customQuery || query;
        if (!finalQuery.trim()) return;

        setLoading(true);
        try {
            const res = await api.getRAGResponse(finalQuery);
            setResponse(res.response);
            setHistory(prev => [{ query: finalQuery, response: res.response }, ...prev]);
            setQuery('');
        } catch (error) {
            console.error("Error asking AI", error);
        } finally {
            setLoading(false);
        }
    };

    // Auto-trigger if query is passed in state
    useEffect(() => {
        if (location.state?.query) {
            handleAskAI(null, location.state.query);
        }
    }, [location.state]);

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-12">
            <div className="text-center space-y-2">
                <h2 className="text-3xl font-bold text-text-primary">Insights Assistant</h2>
                <p className="text-text-secondary">Ask any question about your market data and get AI-powered answers.</p>
            </div>

            <div className="card min-h-[600px] flex flex-col shadow-2xl border-border-dark bg-bg-primary overflow-hidden">
                <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
                    {!response && history.length === 0 && (
                        <div className="flex flex-col items-center justify-center h-full text-center space-y-6 opacity-60">
                            <div className="w-20 h-20 bg-accent-primary/10 rounded-3xl flex items-center justify-center text-accent-primary rotate-3">
                                <Bot className="w-10 h-10" />
                            </div>
                            <div>
                                <p className="text-xl font-bold text-text-primary">Intelligence Engine Activated</p>
                                <p className="text-sm text-text-secondary max-w-sm mx-auto leading-relaxed mt-2 font-medium">
                                    Ask about sentiment shifts, trending topics, or compare product performance across sectors.
                                </p>
                            </div>
                        </div>
                    )}

                    {history.map((chat, idx) => (
                        <div key={idx} className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
                            {/* User Question */}
                            <div className="flex justify-end">
                                <div className="bg-accent-primary text-white rounded-2xl rounded-tr-none px-6 py-4 max-w-[80%] shadow-lg shadow-[0_0_15px_rgba(99,102,241,0.2)]">
                                    <p className="text-sm font-medium">{chat.query}</p>
                                </div>
                            </div>
                            {/* AI Answer */}
                            <div className="flex justify-start">
                                <div className="flex items-start space-x-4 max-w-[90%]">
                                    <div className="w-10 h-10 bg-accent-secondary/10 rounded-xl flex items-center justify-center flex-shrink-0 border border-accent-secondary/20 shadow-sm">
                                        <Bot className="w-6 h-6 text-accent-secondary" />
                                    </div>
                                    <div className="bg-bg-secondary border border-border-dark rounded-3xl rounded-tl-none px-6 py-6 shadow-md text-text-primary relative group">
                                        <div className="flex items-center space-x-2 mb-4">
                                            <Sparkles className="w-4 h-4 text-accent-secondary animate-pulse" />
                                            <span className="text-[10px] font-bold text-text-secondary uppercase tracking-widest">Context-Aware Intelligence</span>
                                        </div>
                                        <p className="text-sm leading-relaxed whitespace-pre-line font-medium text-text-secondary group-hover:text-text-primary transition-colors">{chat.response}</p>
                                        <div className="flex items-center space-x-6 mt-6 pt-6 border-t border-border-dark uppercase text-[10px] font-bold text-text-secondary tracking-wider">
                                            <button className="hover:text-accent-primary flex items-center transition-colors">
                                                <Copy className="w-3.5 h-3.5 mr-1.5" /> Copy
                                            </button>
                                            <button className="hover:text-sentiment-positive flex items-center transition-colors">
                                                <ThumbsUp className="w-3.5 h-3.5 mr-1.5" /> Helpful
                                            </button>
                                            <button className="hover:text-sentiment-negative flex items-center transition-colors">
                                                <ThumbsDown className="w-3.5 h-3.5 mr-1.5" /> Not Helpful
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}

                    {loading && (
                        <div className="flex justify-start animate-pulse">
                            <div className="flex items-start space-x-4">
                                <div className="w-10 h-10 bg-accent-secondary/10 rounded-xl flex items-center justify-center flex-shrink-0 ">
                                    <Bot className="w-6 h-6 text-accent-secondary" />
                                </div>
                                <div className="bg-bg-secondary border border-border-dark rounded-3xl rounded-tl-none px-8 py-5 shadow-sm flex items-center space-x-3">
                                    <div className="w-2 h-2 bg-accent-primary rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                                    <div className="w-2 h-2 bg-accent-primary rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                                    <div className="w-2 h-2 bg-accent-primary rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Input Area */}
                <div className="p-6 border-t border-border-dark bg-bg-secondary rounded-b-xl">
                    <form onSubmit={handleAskAI} className="relative group">
                        <input
                            type="text"
                            value={query}
                            onChange={(e) => setQuery(e.target.value)}
                            placeholder="Ask about market shifts or topic resonance..."
                            className="w-full pl-8 pr-16 py-5 bg-bg-primary border border-border-dark rounded-2xl focus:outline-none focus:ring-4 focus:ring-accent-primary/20 shadow-sm transition-all text-sm font-medium text-text-primary placeholder-text-secondary"
                            disabled={loading}
                        />
                        <button
                            type="submit"
                            disabled={loading || !query.trim()}
                            className="absolute right-3 top-1/2 -translate-y-1/2 w-12 h-12 bg-accent-primary text-white rounded-xl flex items-center justify-center hover:bg-accent-primary/90 hover:scale-[1.02] transition-all active:scale-95 shadow-lg shadow-[0_0_15px_rgba(99,102,241,0.3)] disabled:bg-border-dark disabled:shadow-none disabled:text-text-secondary"
                        >
                            <Send className="w-5 h-5" />
                        </button>
                    </form>
                    <div className="mt-4 flex items-center justify-center space-x-8">
                        <div className="text-[10px] font-bold text-text-secondary flex items-center uppercase tracking-widest">
                            <RefreshCw className="w-3.5 h-3.5 mr-2 text-accent-primary" /> 1,240 tokens remaining
                        </div>
                        <div className="text-[10px] font-bold text-text-secondary flex items-center uppercase tracking-widest">
                            <Database className="w-3.5 h-3.5 mr-2 text-accent-secondary" /> Data Source: Q1 Index
                        </div>
                    </div>
                </div>
            </div>

            {/* Suggested Questions */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <button
                    onClick={() => handleAskAI(null, "What is the general sentiment for renewable energy products?")}
                    className="text-left p-6 bg-bg-secondary border border-border-dark rounded-2xl hover:border-accent-primary/40 hover:bg-bg-primary transition-all group relative overflow-hidden"
                >
                    <div className="relative z-10">
                        <p className="text-[10px] font-bold text-accent-primary mb-2 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">Analyze Context</p>
                        <p className="text-sm font-bold text-text-primary leading-snug group-hover:text-accent-secondary transition-colors">What is the general sentiment for renewable energy products?</p>
                    </div>
                    <Sparkles className="absolute right-4 top-1/2 -translate-y-1/2 w-12 h-12 text-accent-primary/5 -rotate-12 group-hover:scale-110 transition-transform" />
                </button>
                <button
                    onClick={() => handleAskAI(null, "Compare sentiment between Product A and Product C.")}
                    className="text-left p-6 bg-bg-secondary border border-border-dark rounded-2xl hover:border-accent-primary/40 hover:bg-bg-primary transition-all group relative overflow-hidden"
                >
                    <div className="relative z-10">
                        <p className="text-[10px] font-bold text-accent-primary mb-2 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">Compare Performance</p>
                        <p className="text-sm font-bold text-text-primary leading-snug group-hover:text-accent-secondary transition-colors">Compare sentiment between Product A and Product C.</p>
                    </div>
                    <Database className="absolute right-4 top-1/2 -translate-y-1/2 w-12 h-12 text-accent-primary/5 -rotate-12 group-hover:scale-110 transition-transform" />
                </button>
            </div>
        </div>
    );
};

export default RAG;

import React, { useState, useEffect } from 'react';
import {
    BarChart3,
    TrendingUp,
    ArrowUpRight,
    ArrowDownRight,
    Search,
    Clock,
    Zap,
    Target
} from 'lucide-react';
import SentimentPieChart from '../components/charts/SentimentPieChart';
import SentimentTrendChart from '../components/charts/SentimentTrendChart';
import Plot from 'react-plotly.js';
import { useNavigate } from 'react-router-dom';
import DashboardHeader from '../components/layout/DashboardHeader';
import { useDashboard } from '../context/DashboardContext';
import * as api from '../services/api';

const Sentiment = () => {
    const navigate = useNavigate();
    const { range, selectedSector } = useDashboard();
    const [distribution, setDistribution] = useState(null);
    const [trend, setTrend] = useState(null);
    const [productStats, setProductStats] = useState(null);
    const [loading, setLoading] = useState(true);

    const fetchData = async () => {
        setLoading(true);
        try {
            const filters = { range, sector: selectedSector };
            const [d, t, p] = await Promise.all([
                api.getSentimentDistribution(filters),
                api.getSentimentTrend(filters),
                api.getProductSentiment()
            ]);
            setDistribution(d);
            setTrend(t);
            setProductStats(p);
        } catch (error) {
            console.error("Error fetching sentiment data", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, [range, selectedSector]);

    if (loading && !distribution) return (
        <div className="flex items-center justify-center min-h-[400px]">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-accent-primary"></div>
        </div>
    );

    const productChartData = [
        {
            x: productStats?.map(p => p.product),
            y: productStats?.map(p => p.positive),
            name: 'Positive',
            type: 'bar',
            marker: { color: '#10B981', line: { width: 0 } },
            opacity: 0.8
        },
        {
            x: productStats?.map(p => p.product),
            y: productStats?.map(p => p.negative),
            name: 'Negative',
            type: 'bar',
            marker: { color: '#EF4444', line: { width: 0 } },
            opacity: 0.8
        }
    ];

    return (
        <div className="space-y-8 pb-12">
            <DashboardHeader
                title="Sentiment Analytics"
                subtitle="Deep dive into consumer perception and brand performance."
                onRefresh={fetchData}
                loading={loading}
            />

            {/* Premium Comparison Heatmap Placeholder / Interactive Bar */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 card">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xl font-bold text-text-primary flex items-center">
                            <BarChart3 className="w-5 h-5 mr-3 text-accent-primary" />
                            Market Sentiment Matrix
                        </h3>
                        <div className="flex space-x-2">
                            <span className="px-3 py-1 bg-sentiment-positive/10 text-sentiment-positive border border-sentiment-positive/20 text-[10px] font-bold rounded-lg uppercase tracking-wider shadow-[0_0_10px_rgba(34,197,94,0.1)]">Growing Bias</span>
                        </div>
                    </div>
                    <div className="h-96">
                        <Plot
                            data={productChartData}
                            layout={{
                                barmode: 'group',
                                margin: { t: 0, b: 40, l: 40, r: 0 },
                                paper_bgcolor: 'rgba(0,0,0,0)',
                                plot_bgcolor: 'rgba(0,0,0,0)',
                                legend: { orientation: 'h', x: 0.5, xanchor: 'center', y: 1.1, font: { color: '#94a3b8' } },
                                font: { family: 'Inter, sans-serif', color: '#f8fafc' },
                                xaxis: {
                                    tickfont: { color: '#94a3b8' },
                                    showgrid: false
                                },
                                yaxis: {
                                    gridcolor: '#1e293b',
                                    tickfont: { color: '#94a3b8' },
                                    zeroline: false
                                },
                                bargap: 0.4
                            }}
                            useResizeHandler={true}
                            className="w-full h-full"
                            config={{ displayModeBar: false, responsive: true }}
                        />
                    </div>
                </div>

                <div className="space-y-6">
                    <div className="card bg-gradient-to-br from-[#1e1b4b] to-[#312e81] text-white border-indigo-500/30 shadow-[0_0_30px_rgba(79,70,229,0.15)] relative overflow-hidden group">
                        <div className="relative z-10">
                            <div className="flex items-center space-x-2 text-accent-secondary mb-4 font-semibold uppercase tracking-widest ">
                                <Zap className="w-4 h-4" />
                                <span className="text-[10px] font-bold tracking-widest ">Real-time Signal</span>
                            </div>
                            <h4 className="text-2xl font-bold mb-2">'AI Transparency' is peaking</h4>
                            <p className="text-indigo-200 text-sm mb-6 opacity-90 font-medium leading-relaxed">
                                Consumer trust in transparent AI models has increased by 22% in the {range === 'L7D' ? 'last week' : 'last month'} within {selectedSector}.
                            </p>
                            <button
                                onClick={() => navigate('/dashboard/topics')}
                                className="w-full py-3 bg-accent-primary text-white rounded-xl font-bold text-sm hover:scale-[1.02] transition-all shadow-[0_0_20px_rgba(99,102,241,0.4)]"
                            >
                                View Cluster Details
                            </button>
                        </div>
                        <div className="absolute top-0 right-0 w-1/2 h-full bg-gradient-to-l from-bg-primary/50 to-transparent pointer-events-none"></div>
                    </div>

                    <div className="card border-border-dark bg-bg-primary">
                        <h4 className="text-sm font-bold text-text-primary mb-4 flex items-center uppercase tracking-wider ">
                            <Target className="w-4 h-4 mr-2 text-accent-primary " />
                            Sentiment Drivers
                        </h4>
                        <div className="space-y-4">
                            {[
                                { label: 'Pricing Strategy', score: 82, trend: 'up' },
                                { label: 'UI Responsiveness', score: 64, trend: 'down' },
                                { label: 'Feature Set', score: 91, trend: 'up' }
                            ].map((driver, i) => (
                                <div key={i} className="flex items-center justify-between">
                                    <span className="text-sm text-text-secondary font-semibold">{driver.label}</span>
                                    <div className="flex items-center space-x-3">
                                        <div className="w-24 h-1.5 bg-border-dark rounded-full overflow-hidden">
                                            <div className="h-full bg-accent-primary shadow-[0_0_8px_rgba(99,102,241,0.8)] rounded-full" style={{ width: `${driver.score}%` }}></div>
                                        </div>
                                        <span className="text-xs font-bold text-text-primary">{driver.score}%</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 ">
                <div className="card">
                    <h3 className="text-lg font-bold text-text-primary mb-6 flex items-center uppercase tracking-widest">
                        <Clock className="w-5 h-5 mr-3 text-accent-primary" />
                        Momentum Trajectory
                    </h3>
                    <div className="h-72">
                        <SentimentTrendChart data={trend} />
                    </div>
                </div>

                <div className="card flex flex-col items-center justify-center p-8 bg-bg-secondary relative overflow-hidden">
                    <div className="relative z-10 text-center ">
                        <h3 className="text-lg font-bold text-text-primary mb-6 uppercase tracking-widest ">Overall Distribution</h3>
                        <div className="h-64 w-64">
                            <SentimentPieChart data={distribution} />
                        </div>
                    </div>
                    {/* Background decoration */}
                    <div className="absolute top-0 right-0 w-32 h-32 bg-accent-primary rounded-full -mr-16 -mt-16 opacity-[0.03] blur-2xl"></div>
                    <div className="absolute bottom-0 left-0 w-24 h-24 bg-accent-secondary rounded-full -ml-12 -mb-12 opacity-[0.03] blur-2xl"></div>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 ">
                <div className="bg-bg-secondary p-6 rounded-2xl border border-sentiment-positive/20 group hover:scale-[1.02] hover:shadow-[0_0_20px_rgba(34,197,94,0.1)] transition-all cursor-pointer">
                    <div className="flex items-center justify-between mb-4">
                        <div className="w-10 h-10 bg-sentiment-positive/10 rounded-xl flex items-center justify-center text-sentiment-positive ">
                            <ArrowUpRight className="w-5 h-5" />
                        </div>
                        <span className="text-[10px] font-bold text-sentiment-positive uppercase tracking-widest">Growth leader</span>
                    </div>
                    <h4 className="text-xl font-bold text-text-primary">Product Delta</h4>
                    <p className="text-sm text-sentiment-positive mt-1 font-semibold ">92% Positive Ratio</p>
                </div>

                <div className="bg-bg-secondary p-6 rounded-2xl border border-sentiment-negative/20 group hover:scale-[1.02] hover:shadow-[0_0_20px_rgba(239,68,68,0.1)] transition-all cursor-pointer">
                    <div className="flex items-center justify-between mb-4">
                        <div className="w-10 h-10 bg-sentiment-negative/10 rounded-xl flex items-center justify-center text-sentiment-negative">
                            <ArrowDownRight className="w-5 h-5" />
                        </div>
                        <span className="text-[10px] font-bold text-sentiment-negative uppercase tracking-widest ">Risk threshold</span>
                    </div>
                    <h4 className="text-xl font-bold text-text-primary">Product Gamma</h4>
                    <p className="text-sm text-sentiment-negative mt-1 font-semibold ">Explosive negative spike (+12%)</p>
                </div>

                <div className="bg-bg-secondary p-6 rounded-2xl border border-accent-secondary/20 group hover:scale-[1.02] hover:shadow-[0_0_20px_rgba(34,211,238,0.1)] transition-all cursor-pointer">
                    <div className="flex items-center justify-between mb-4">
                        <div className="w-10 h-10 bg-accent-secondary/10 rounded-xl flex items-center justify-center text-accent-secondary">
                            <TrendingUp className="w-5 h-5" />
                        </div>
                        <span className="text-[10px] font-bold text-accent-secondary uppercase tracking-widest ">Stability index</span>
                    </div>
                    <h4 className="text-xl font-bold text-text-primary">Product Alpha</h4>
                    <p className="text-sm text-accent-secondary mt-1 font-semibold ">Linear growth in sentiment</p>
                </div>
            </div>
        </div>
    );
};

export default Sentiment;

import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Mail, Lock, User, Phone, Loader2, ArrowRight } from 'lucide-react';
import { authService } from '../services/authService';
import AuthLayout from '../components/auth/AuthLayout';

const Signup = () => {
    const navigate = useNavigate();
    const location = useLocation();

    const from = location.state?.from?.pathname || '/dashboard';

    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [phoneNumber, setPhoneNumber] = useState('');
    const [otp, setOtp] = useState('');
    const [otpSent, setOtpSent] = useState(false);
    const [showPhoneLogin, setShowPhoneLogin] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (password !== confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        setIsSubmitting(true);
        try {
            await authService.signUp(email, password);
            navigate(from, { replace: true });
        } catch (err) {
            setError(err.message || 'Registration failed. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleGoogleLogin = async () => {
        setIsSubmitting(true);
        try {
            await authService.signInWithGoogle();
            // Google OAuth redirects are handled in authService itself
        } catch (err) {
            setError('Google signup failed. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handlePhoneSignup = async (e) => {
        e.preventDefault();
        setError('');
        setIsSubmitting(true);
        try {
            await authService.signInWithOtp(phoneNumber);
            setOtpSent(true);
        } catch (err) {
            setError(err.message || 'Failed to send OTP. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleVerifyOtp = async (e) => {
        e.preventDefault();
        setError('');
        setIsSubmitting(true);
        try {
            await authService.verifyOtp(phoneNumber, otp);
            navigate(from, { replace: true });
        } catch (err) {
            setError(err.message || 'Invalid OTP. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <AuthLayout
            mode="signup"
            title="Create Account"
            subtitle="or use your email for registration"
            footerText="Already have an account?"
            footerLink="/login"
            footerLinkText="Sign In"
        >
            {error && (
                <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 text-sm rounded-r-lg animate-shake">
                    {error}
                </div>
            )}

            {!showPhoneLogin ? (
                <form className="space-y-5" onSubmit={handleSubmit}>
                    <div className="relative group">
                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                            <User className="w-5 h-5" />
                        </div>
                        <input
                            type="text"
                            required
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                            placeholder="Name"
                        />
                    </div>

                    <div className="relative group">
                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                            <Mail className="w-5 h-5" />
                        </div>
                        <input
                            type="email"
                            required
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                            placeholder="Email"
                        />
                    </div>

                    <div className="relative group">
                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                            <Lock className="w-5 h-5" />
                        </div>
                        <input
                            type="password"
                            required
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                            placeholder="Password"
                        />
                    </div>

                    <div className="relative group">
                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                            <Lock className="w-5 h-5" />
                        </div>
                        <input
                            type="password"
                            required
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                            className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                            placeholder="Confirm Password"
                        />
                    </div>

                    <div className="flex items-center gap-2 px-2">
                        <input
                            id="terms"
                            type="checkbox"
                            required
                            className="w-4 h-4 text-teal-600 border-gray-300 rounded focus:ring-teal-500"
                        />
                        <label htmlFor="terms" className="text-xs text-gray-500">
                            I agree to the <span className="text-teal-600 font-semibold cursor-pointer">Terms</span> & <span className="text-teal-600 font-semibold cursor-pointer">Privacy Policy</span>
                        </label>
                    </div>

                    <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full bg-teal-500 text-white font-bold py-4 rounded-full shadow-lg shadow-teal-500/30 hover:bg-teal-600 hover:shadow-teal-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center"
                    >
                        {isSubmitting ? (
                            <Loader2 className="w-6 h-6 animate-spin" />
                        ) : (
                            <>
                                SIGN UP
                                <ArrowRight className="w-5 h-5 ml-2" />
                            </>
                        )}
                    </button>

                    <div className="relative flex items-center py-2">
                        <div className="flex-grow border-t border-gray-200"></div>
                        <span className="flex-shrink-0 mx-4 text-gray-400 text-sm font-medium">OR</span>
                        <div className="flex-grow border-t border-gray-200"></div>
                    </div>

                    <button
                        type="button"
                        onClick={handleGoogleLogin}
                        disabled={isSubmitting}
                        className="w-full bg-white border border-gray-300 text-gray-700 font-bold py-3.5 rounded-full hover:bg-gray-50 hover:shadow-md transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center shadow-sm"
                    >
                        <svg className="w-5 h-5 mr-3" viewBox="0 0 24 24">
                            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                        </svg>
                        Continue with Google
                    </button>

                    <button
                        type="button"
                        onClick={() => setShowPhoneLogin(true)}
                        className="w-full text-center text-sm font-semibold text-gray-500 hover:text-teal-600 flex items-center justify-center gap-2 mt-4"
                    >
                        <Phone className="w-4 h-4" />
                        Use Phone Number
                    </button>
                </form>
            ) : (
                <form className="space-y-5" onSubmit={otpSent ? handleVerifyOtp : handlePhoneSignup}>
                    {!otpSent ? (
                        <>
                            <div className="relative group">
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                                    <Phone className="w-5 h-5" />
                                </div>
                                <input
                                    type="tel"
                                    required
                                    value={phoneNumber}
                                    onChange={(e) => setPhoneNumber(e.target.value)}
                                    className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                                    placeholder="Phone Number (e.g., +1234567890)"
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={isSubmitting}
                                className="w-full bg-teal-500 text-white font-bold py-4 rounded-full shadow-lg shadow-teal-500/30 hover:bg-teal-600 hover:shadow-teal-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center"
                            >
                                {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : 'SEND OTP'}
                            </button>
                        </>
                    ) : (
                        <>
                            <div className="relative group">
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-teal-500 transition-colors">
                                    <Lock className="w-5 h-5" />
                                </div>
                                <input
                                    type="text"
                                    required
                                    value={otp}
                                    onChange={(e) => setOtp(e.target.value)}
                                    className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl input-focus text-gray-700 font-medium"
                                    placeholder="Enter OTP"
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={isSubmitting}
                                className="w-full bg-teal-500 text-white font-bold py-4 rounded-full shadow-lg shadow-teal-500/30 hover:bg-teal-600 hover:shadow-teal-500/40 transition-all active:scale-95 disabled:opacity-50 flex justify-center items-center"
                            >
                                {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : 'VERIFY OTP'}
                            </button>
                        </>
                    )}

                    <button
                        type="button"
                        onClick={() => {
                            setShowPhoneLogin(false);
                            setOtpSent(false);
                            setOtp('');
                        }}
                        className="w-full text-center text-sm font-semibold text-gray-500 hover:text-teal-600"
                    >
                        Back to Email Signup
                    </button>
                </form>
            )}
        </AuthLayout>
    );
};

export default Signup;

import { mockData } from '../mock/mockData';

const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

export const getStats = async (filters = {}) => {
    await delay(500);
    // Simulate filtering impact
    const baseStats = { ...mockData.stats };
    if (filters.range === 'L30D') baseStats.totalDataPoints *= 4;
    return baseStats;
};

export const getSentimentDistribution = async (filters = {}) => {
    await delay(500);
    return mockData.sentimentDistribution;
};

export const getSentimentTrend = async (filters = {}) => {
    await delay(500);
    const trend = [...mockData.sentimentTrend];
    if (filters.range === 'L7D') return trend.slice(-7);
    return trend;
};

